def read_config(filename):
    try:
        file = open(filename)
    except FileNotFoundError:
        print(f"Config file '{filename}' not found. Using defaults.")
        return {}
    else:
        content = file.read()
        file.close()
        print("Config loaded successfully.")
        return content
    finally:
        print("read_config() finished.")

read_config("settings.txt")

